def range_summary(nums):
    if not nums:
        return ''
    runs = []
    current_start, current_end = nums[0], nums[0]
    for num in nums:
        if num > current_end + 1:
            runs.append(f'{current_start}-{current_end}' if current_start != current_end else str(current_start))
            current_start, current_end = num, num
    runs.append(f'{current_start}-{current_end}' if current_start != current_end else str(current_start))
    return ', '.join(runs)
